#!/usr/bin/env python3
import requests
import sys

def check_health(base_url='http://localhost:8080'):
    endpoints = ['/health', '/api/v1/status', '/metrics']
    for ep in endpoints:
        resp = requests.get(f'{base_url}{ep}', timeout=5)
        status = 'OK' if resp.status_code == 200 else 'FAIL'
        print(f'{ep}: {status} ({resp.status_code})')

if __name__ == '__main__':
    url = sys.argv[1] if len(sys.argv) > 1 else 'http://localhost:8080'
    check_health(url)

